function normalizeJs(js) {
  return js.replaceAll('.p="/_next/"', `.p="${basePath}/_next/"`);
}

await mkdir(distDir, { recursive: true });
await writeFile(path.join(distDir, 'search-widget.js'), buildSearchWidgetJs());

const files = await walk(distDir);

for (const file of files) {
  const info = await stat(file);
  if (!info.isFile()) {
    continue;
  }

  if (file.endsWith('.html')) {
    const route = pageRoute(file);
    const html = await readFile(file, 'utf8');
    await writeFile(file, normalizeHtml(html, route));
  }

  if (file.includes(`${path.sep}_next${path.sep}`) && file.endsWith('.js')) {
    const js = await readFile(file, 'utf8');
    await writeFile(file, normalizeJs(js));
  }
}

const apiWelcomeRedirectDir = path.join(distDir, 'api-reference', 'boas-vindas');
const apiWelcomeTarget = `${basePath}/api-reference/como-executar-service/`;
const apiWelcomeRedirect = redirectPage(apiWelcomeTarget, 'Como executar um service');

await mkdir(apiWelcomeRedirectDir, { recursive: true });
await writeFile(path.join(apiWelcomeRedirectDir, 'index.html'), apiWelcomeRedirect);

for (const staticFile of [
  'llms.txt',
  'llms-small.txt',
  'llms-full.txt',
  'llms-api-reference.txt',
  'services-catalog.json',
  'services-catalog.min.json',
  'mcp-manifest.json',
  'guides-search-index.json',
]) {
  try {
    await copyFile(path.join(process.cwd(), staticFile), path.join(distDir, staticFile));
  } catch {
    // Optional files. They are generated by `npm run generate:llms`.
  }
}

await copyDir(path.join(process.cwd(), 'examples'), path.join(distDir, 'examples'));

if (basePath !== '') {
  const subpathDir = path.join(distDir, basePath.slice(1));
  await copyPagesSiteToSubpath(distDir, subpathDir);
  await writeFile(path.join(distDir, 'index.html'), redirectPage(`${basePath}/`, 'api-docs-idcerberus'));
}

if (customDomain) {
  await writeFile(path.join(distDir, 'CNAME'), `${customDomain}\n`);
}
